Функция ПолучитьСуммарныйДолгКонтрагента(КонтрагентСсылка) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
	|	СУММА(ВЗАИМОРАСЧЕТЫОСТАТКИ.СуммаОстаток) КАК СуммарныйДолг
	|ИЗ
	|	РегистрНакопления.Взаиморасчеты.Остатки КАК ВЗАИМОРАСЧЕТЫОСТАТКИ
	|		ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.Договоры КАК Договоры
	|		ПО ВЗАИМОРАСЧЕТЫОСТАТКИ.Договор = Договоры.Ссылка
	|ГДЕ
	|	Договоры.Владелец = &Контрагент
	|	И ВЗАИМОРАСЧЕТЫОСТАТКИ.СуммаОстаток > 0";

	Запрос.УстановитьПараметр("Контрагент", КонтрагентСсылка);
	Результат = Запрос.Выполнить();

	Если Результат.Пустой() Тогда
		Возврат 0;
	Иначе
		Выборка = Результат.Выбрать();
		Выборка.Следующий();
		Возврат Выборка.СуммарныйДолг;
	КонецЕсли;

КонецФункции
